(window.webpackJsonp=window.webpackJsonp||[]).push([[11],{"5Epl":function(e,a,i){"use strict";i.d(a,"a",(function(){return j}));var o=i("q1tI"),n=i.n(o),r=i("R/WZ"),t=i("ofer"),l=Object(r.a)({figure:{margin:"0"},image:{width:"100%",maxHeight:"700px",borderRadius:"7px",display:"block",margin:"auto"}});function j(e){var a=e.src,i=e.caption,o=e.center,r=l();return n.a.createElement("figure",{className:r.figure},n.a.createElement("img",{src:a,alt:i,className:r.image,style:o?{width:"auto",margin:"auto"}:null}),n.a.createElement(t.a,{variant:"caption",paragraph:!0,align:o?"center":"left"},i))}},NOiM:function(e,a,i){"use strict";i.r(a);var o=i("q1tI"),n=i.n(o),r=i("ofer"),t=i("mc/u"),l=i("5Epl"),j=i("dmUO"),s=i.n(j),d=i("ieaM"),p=i.n(d),m=i("pvf1"),v=i.n(m);a.default=function(){return n.a.createElement(t.a,{title:"Utrjen vhod"},n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Gradišče je imelo dva vhoda, severnega in južnega, vsi drugi današnji prehodi skozi okop so nastali kasneje. Glavno vlogo je imel južni vhod, pred katerim je bilo na rezultatih zračnega laserskega skeniranja prvič mogoče prepoznati dostopno pot, ki je po svojem načinu izgradnje edinstvena v širšem prostoru. Gre za pot dolžine okoli 180 m in širine 4–5 m, ki se začne pri železarsko-talilniškem območju na Branževcu in vodi do vhoda v naselje. Pot na tej razdalji večkrat zavije, na obeh straneh je utrjena in ob tem dvakrat dopolnjena s prečnima okopoma. Z izkopavanjem tistega bližje naselbini so arheologi ugotovili, da gre za ostanke kamnitega zidu, ki je bil širok pribl. 4 m. Kljub slabše ohranjenim ostalinam je bilo jasno prepoznavno njegovo zunanje in notranje lice, grajeno iz večjih kamnov. Zid je imel še dve liniji večjih kamnov v notranjosti. Vmesni prostori so bili, podobno kot je bilo to pri obzidju okoli gradišča, zapolnjeni z manj šimi kamni in drobirjem."),n.a.createElement(l.a,{src:v.a,caption:"Delno rekonstruiran (2020) skoraj 4 m širok dvojni zid ob dohodni poti."}),n.a.createElement(l.a,{src:s.a,caption:"Digitalni model ostalin več kot 3 m širokega prečnega utrdbenega zidu."}),n.a.createElement(r.a,{variant:"body1",paragraph:!0},"Utrjena pot je prebivalcem Cvingerja zagotavljala dodatno varnost in nadzor nad prišleki. Treba jo je razumeti skupaj z drugimi deli najdišča, ki je premišljeno organizirano. Šele z zračnim laserskim snemanjem je bilo namreč mogoče prepoznati tudi ugreznjene poti, ki se družijo v koridor premikanja in jih razumemo kot ostanke nekdanjih poti. Te vodijo najprej mimo gomilnega grobišča na Branževcu, mimo talilniškega območja in nato skozi utrjen dostop do naselja. Takšna ureditev prostora v okolici gradišča ni edinstvena, a nam predstavlja doslej slabo poznan vidik železnodobne družbe, ki si ga poskušamo razložiti. Obiskovalec, ki je prihajal na Cvinger, je naprej šel skozi nekropolo (svet mrtvih), kjer je spoznal slavo preteklih rodov. Nadaljeval je mimo talilnic, ki so zagotavljale blagostanje tukajšnje skupnosti. Nato je v zadnjih metrih moral prestati še preverjanje ob utrjenih prehodih na dostopni poti, da je lahko vstopil v naselbino. Morda boste o tem razmišljali tudi vi, današnji obiskovalci Cvingerja, ko boste naslednjič hodili po naši arheološki poti."),n.a.createElement(l.a,{src:p.a,caption:"Zračni posnetek, iz katerega je razviden potek dvojnega zidu."}))}},dmUO:function(e,a,i){e.exports=i.p+"static/fotoskica-e0d173cbd2acbe188e62ee1b716e4766.jpg"},ieaM:function(e,a,i){e.exports=i.p+"static/tloris-4def6eed80653dae9a11c8e63ec58eeb.jpg"},pvf1:function(e,a,i){e.exports=i.p+"static/vhod-e6b684f483bdce2cec119e16f1147f34.jpg"}}]);
